const frame=make('section','frame'); frame.setAttribute('aria-label',title);
const heading=make('header','heading'); heading.appendChild(make('div','eyebrow','Weighted scorecard')); heading.appendChild(make('h2','',title));
heading.appendChild(make('div','meta',options.length+' option'+(options.length===1?'':'s')+' · '+metrics.length+' normalized metrics · scale '+scale));
frame.appendChild(heading);
if(!metrics.length||!options.length){
  frame.appendChild(make('div','empty','Add options and metrics to build the scorecard.'));
}else{
  const scroll=make('div','scroll'); const grid=make('div','grid'); grid.style.setProperty('--metric-count',String(metrics.length));
  const head=make('div','grid-row head'); head.appendChild(make('div','','Option'));
  metrics.forEach((metric) => { const cell=make('div','metric-head',metric&&metric.label?String(metric.label):'Metric'); const weight=typeof metric.weight==='number'?metric.weight:1; cell.appendChild(make('span','weight','weight '+weight)); head.appendChild(cell); });
  head.appendChild(make('div','metric-head','Total')); grid.appendChild(head);
  options.forEach((option) => {
    const recommended=option&&option.highlight===true; const row=make('div','grid-row option-row'+(recommended?' recommended':''));
    const optionCell=make('div','option-cell');
    if(recommended) optionCell.appendChild(make('span','ribbon','Recommended'));
    optionCell.appendChild(make('div','option-name',option&&option.name!=null?String(option.name):'Untitled'));
    if(option&&option.note) optionCell.appendChild(make('div','option-note',String(option.note)));
    row.appendChild(optionCell);
    let weighted=0; let weights=0;
    metrics.forEach((metric) => {
      const raw=option&&option.scores&&typeof option.scores[metric.key]==='number'?option.scores[metric.key]:0;
      const value=Math.max(0,Math.min(scale,Number.isFinite(raw)?raw:0)); const weight=typeof metric.weight==='number'&&Number.isFinite(metric.weight)?Math.max(0,metric.weight):1;
      weighted+=value*weight; weights+=weight;
      const cell=make('div','metric-cell'); const top=make('div','metric-top'); top.appendChild(make('span','',metric&&metric.shortLabel?String(metric.shortLabel):String(metric.label||metric.key||'Metric'))); top.appendChild(make('span','metric-value',String(Math.round(value))));
      cell.appendChild(top); const track=make('div','track'); track.setAttribute('role','meter'); track.setAttribute('aria-valuemin','0'); track.setAttribute('aria-valuemax',String(scale)); track.setAttribute('aria-valuenow',String(value));
      const fill=make('div','fill'); fill.style.width=(value/scale*100)+'%'; track.appendChild(fill); cell.appendChild(track); row.appendChild(cell);
    });
    const computed=weights?weighted/weights:0; const rawTotal=typeof option.total==='number'&&Number.isFinite(option.total)?option.total:computed; const total=Math.max(0,Math.min(scale,rawTotal));
    const totalCell=make('div','total-cell'); const badge=make('div','total'); badge.setAttribute('aria-label','Total '+Math.round(total)+' out of '+scale); badge.appendChild(make('span','',String(Math.round(total)))); badge.appendChild(make('span','out-of','/'+scale)); totalCell.appendChild(badge); row.appendChild(totalCell);
    grid.appendChild(row);
  });
  scroll.appendChild(grid); frame.appendChild(scroll);
}
